cd /home/user/altair_task && python3 -c "
import json, re

with open('output/chart.html', 'r') as f:
    html = f.read()

match = re.search(r'var\s+spec\s*=\s*({.*?});', html, re.DOTALL)
if not match:
    match = re.search(r'\"spec\"\s*:\s*({.*})', html, re.DOTALL)
spec = json.loads(match.group(1))

errors = []

# 1. Faceted on year (ordinal)
facet = spec.get('facet', {})
col = facet.get('column', {})
if col.get('field') != 'year' or col.get('type') != 'ordinal':
    errors.append('NOT faceted on year:O')
else:
    print('OK: faceted on year:O')

# 2. Contains a layer
inner = spec.get('spec', {})
layers = inner.get('layer', [])
if len(layers) < 2:
    errors.append(f'Expected >=2 layers, got {len(layers)}')
else:
    print(f'OK: {len(layers)} layers found')

# 3. First layer: bar mark
bar_layer = layers[0]
if bar_layer.get('mark', {}).get('type') != 'bar':
    errors.append('First layer mark is not bar')
else:
    print('OK: first layer is bar')

# 4. Bar layer: x=site:N sorted by mean(yield) desc
bx = bar_layer['encoding']['x']
if bx.get('field') != 'site' or bx.get('type') != 'nominal':
    errors.append('Bar x encoding not site:N')
else:
    sort = bx.get('sort', {})
    if sort.get('field') == 'yield' and sort.get('op') == 'mean' and sort.get('order') == 'descending':
        print('OK: bar x sorted by mean(yield) descending')
    else:
        errors.append(f'Bar x sort incorrect: {sort}')

# 5. Bar layer: y=mean(yield):Q
by = bar_layer['encoding']['y']
if by.get('aggregate') == 'mean' and by.get('field') == 'yield' and by.get('type') == 'quantitative':
    print('OK: bar y is mean(yield):Q')
else:
    errors.append(f'Bar y encoding incorrect: {by}')

# 6. Bar layer: xOffset=variety:N
bxo = bar_layer['encoding'].get('xOffset', {})
if bxo.get('field') == 'variety' and bxo.get('type') == 'nominal':
    print('OK: bar xOffset is variety:N')
else:
    errors.append(f'Bar xOffset incorrect: {bxo}')

# 7. Bar layer: color=variety:N with tableau10
bc = bar_layer['encoding']['color']
if bc.get('field') == 'variety' and bc.get('scale', {}).get('scheme') == 'tableau10':
    print('OK: bar color is variety:N with tableau10')
else:
    errors.append(f'Bar color incorrect: {bc}')

# 8. Tick layer: mark is tick or rule
tick_layer = layers[1]
tick_mark = tick_layer.get('mark', {})
if isinstance(tick_mark, dict):
    tick_type = tick_mark.get('type')
else:
    tick_type = tick_mark
if tick_type in ('tick', 'rule'):
    print(f'OK: tick layer mark is {tick_type}')
else:
    errors.append(f'Tick layer mark is not tick/rule: {tick_mark}')

# 9. Tick layer: has aggregate transform
transforms = tick_layer.get('transform', [])
has_agg = any(
    t.get('aggregate') is not None for t in transforms
)
if has_agg:
    agg_t = [t for t in transforms if t.get('aggregate')][0]
    agg_ops = agg_t.get('aggregate', [])
    groupby = agg_t.get('groupby', [])
    has_mean_yield = any(
        a.get('op') == 'mean' and a.get('field') == 'yield' for a in agg_ops
    )
    has_site_year = 'site' in groupby and 'year' in groupby
    if has_mean_yield and has_site_year:
        print('OK: tick layer has aggregate transform: mean(yield) groupby [site, year]')
    else:
        errors.append(f'Tick aggregate transform incomplete: ops={agg_ops}, groupby={groupby}')
else:
    errors.append('Tick layer has no aggregate transform')

# 10. Title is object with text and subtitle
title = spec.get('title', {})
if isinstance(title, dict):
    t = title.get('text', '')
    s = title.get('subtitle', '')
    if t and s:
        print(f'OK: title object with text=\"{t}\" and subtitle=\"{s}\"')
    else:
